impl HashMap_i32_i32 {
    fn get_or(self, key: i32, default: i32) -> i32 {
        if self.contains(key) == 1 {
            return self.get(key)
        }
        return default
    }

    fn get_or_insert(self, key: i32, value: i32) -> i32 {
        if self.contains(key) == 1 {
            return self.get(key)
        }
        let _ = self.insert(key, value)
        return value
    }
}
